diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..f162c9180a67 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4629,6 +4629,18 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
     if (match(TrueVal, m_ZeroInt()))
       return ConstantInt::getFalse(Cond->getType());
   }
+  // select (select a, b, false), true, b -> b
+  // select (select a, false, b), b, true -> b
+  if (Cond->getType()->isIntegerTy(1) && TrueVal->getType()->isIntegerTy(1)) {
+    Value *A, *B;
+    if (match(Cond, m_Select(m_Value(A), m_Value(B), m_Zero())) &&
+        match(TrueVal, m_One()) && match(FalseVal, m_Specific(B)))
+      return B;
+    if (match(Cond, m_Select(m_Value(A), m_Zero(), m_Value(B))) &&
+        match(TrueVal, m_Specific(B)) && match(FalseVal, m_One()))
+      return B;
+  }
+

